import threading
import time

WATCHDOG_S = 1.0


def _run(targets):
    errors = []
    barrier = threading.Barrier(len(targets) + 1)

    def wrap(fn):
        def go():
            try:
                barrier.wait()
                fn()
            except BaseException as exc:  # noqa: BLE001 - relayed below
                errors.append(exc)
        return go

    threads = [threading.Thread(target=wrap(t), daemon=True) for t in targets]
    for t in threads:
        t.start()
    barrier.wait()
    deadline = time.monotonic() + WATCHDOG_S
    for t in threads:
        t.join(max(0.0, deadline - time.monotonic()))
    if errors:
        raise errors[0]
    if any(t.is_alive() for t in threads):
        raise RuntimeError(
            "threads did not finish within the watchdog - deadlock or a missed signal"
        )
def drive(cls, args, record):
    inst = cls()
    calls = {
        1: lambda: inst.first(lambda: record("first")),
        2: lambda: inst.second(lambda: record("second")),
        3: lambda: inst.third(lambda: record("third")),
    }
    _run([calls[i] for i in args[0]])

